def render_page(filename, title, subtitle, desc, profile, route_count=0):
    path_flow={'command':['Objective','Mission Contract','AGI Agents','AGI Job','AGI Node','ProofBundle','Evidence Docket','Validation','Chronicle','Reusable Capability'],
               'holy':['Mission','Work','Proof','Validation','Verified Experience','Chronicle','Capability','Settlement Simulation','Reinvestment','Harder Mission'],
               'rsi':['TARGET','EMIT','FILTER','ATLAS','TEST-PLAN','EVAL','INSERT','PROMOTE','Dossier','Governance'],
               'move37':['Recognize','Reproduce','Stress-test','Persistence','Dossier','Council'],
               'loop':['Write loop','Separate roles','Contract first','Write to disk','Read traces','Score taste','Find bottleneck','Restart'],
               'agents':['Identify','Role graph','AGI Job','Tools','Node handoff','ProofBundle','Evidence Docket','Validate','Chronicle'],
               'node':['Identity','Runtime pins','Worker','Validator','Sentinel','Metering','Artifacts','Rollback'],
               'validation':['Authority','Commit','Replay','Review','Risk','Challenge','Certificate','Decision'],
               'contracts':['Atlas','Registry','Jobs','Proof rail','Token boundary','Settlement simulation','Reviewer packet'],
               'proof':['Claims','Baselines','Environment','Proof packets','Replay','Risk/cost','Validator report','Chronicle'],
               'search':['Question','Intent','Route map','Rank','Explain','Open'],
               'trust':['Data','Wallet','Token','Privacy','Security','Claims']}.get(profile, ['Objective','Agents','Proof','Validate','Chronicle'])
    flow=''.join(f'<div class="goalos-v56-step"><b>{i+1:02d}</b><strong>{html.escape(s)}</strong><span>{"browser-local gate" if i<len(path_flow)-1 else "decision state"}</span></div>' for i,s in enumerate(path_flow))
    metric_data=[('298+','Public pages','complete surface preserved'),('254+','Current routes','canonical routes indexed'),('0','External actions','browser-local demos'),('Always','Boundary','no wallet / no transaction')]
    metrics=''.join(f'<div class="goalos-v56-metric"><strong>{a}</strong><span>{b}</span><p>{c}</p></div>' for a,b,c in metric_data)
    cards=''.join(f'<div class="goalos-v56-mini"><span>{label}</span><strong>{val}</strong></div>' for label,val in [('Mission profile',profile),('Route',filename),('Boundary','preserved'),('Authority','review required')])
    return f'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{html.escape(title)} — GoalOS</title><meta name="description" content="{html.escape(desc[:150])}"><link rel="stylesheet" href="assets/goalos-sovereign-proof-machine-os-v56.css"><script defer src="assets/goalos-route-registry-v56.js"></script><script defer src="assets/goalos-sovereign-proof-machine-os-v56.js"></script></head><body class="goalos-v56" data-goalos-page="{profile}"><div class="goalos-v56-shell">{nav()}<section class="goalos-v56-page"><main class="goalos-v56-card"><div class="goalos-v56-kicker">GoalOS Sovereign Proof Machine</div><h1 class="goalos-v56-title">{html.escape(title)}<br><em>{html.escape(subtitle)}</em></h1><p class="goalos-v56-copy">{html.escape(desc)}</p><div class="goalos-v56-actions"><button class="goalos-v56-btn goalos-v56-primary" data-goalos-v56-run>Run end-to-end demo</button><button class="goalos-v56-btn" data-goalos-v56-ask>Ask GoalOS</button><a class="goalos-v56-btn" href="all-pages.html">All Pages</a></div><div class="goalos-v56-boundary">No user data. No user funds. No wallet. No transaction. No backend call. No production authority. Human review required.</div></main><aside class="goalos-v56-console"><canvas></canvas><div class="goalos-v56-console-inner"><div class="goalos-v56-status"><strong>Live Mission Console</strong><span class="goalos-v56-pill">ready</span></div><div class="goalos-v56-agent-matrix"><div class="goalos-v56-agent is-active">α</div><div class="goalos-v56-agent">AGENTS</div><div class="goalos-v56-agent">JOB</div><div class="goalos-v56-agent">NODE</div><div class="goalos-v56-agent">PROOF</div><div class="goalos-v56-agent">VALIDATE</div></div><div class="goalos-v56-grid">{cards}</div></div></aside></section><section class="goalos-v56-section"><div class="goalos-v56-kicker">Mission path</div><h2>Autonomous, visual, proof-gated.</h2><div class="goalos-v56-flow">{flow}</div></section><section class="goalos-v56-section"><div class="goalos-v56-kicker">Canonical surface</div><h2>Everything routes from here.</h2><div class="goalos-v56-metrics">{metrics}</div></section></div></body></html>'''

def RENDER_ALL(routes):
    groups={}
    for r in routes:
        prof=PAGES.get(r,('', '', '', 'default'))[3] if r in PAGES else 'additional'
        groups.setdefault(prof,[]).append(r)
    rows=[]
    for g in sorted(groups):
        for r in sorted(groups[g]):
            title=PAGES.get(r,(r.replace('.html','').replace('-',' ').title(),'','',''))[0]
            rows.append(f'<a class="goalos-v56-route" href="{html.escape(r)}"><span>{html.escape(g)}</span><strong>{html.escape(title)}</strong><span>Open →</span></a>')
    base=render_page('all-pages.html','All Pages','Everything routeable.','The complete public surface is grouped by purpose. Canonical pages are promoted and preserved routes remain discoverable.','search')
    return base.replace('<section class="goalos-v56-section"><div class="goalos-v56-kicker">Canonical surface</div><h2>Everything routes from here.</h2><div class="goalos-v56-metrics">', '<section class="goalos-v56-section"><div class="goalos-v56-kicker">Route inventory</div><h2>Canonical + preserved routes.</h2><input class="goalos-v56-search" id="routeFilter" placeholder="Filter all pages..."><script>document.addEventListener("input",e=>{if(e.target.id==="routeFilter"){const q=e.target.value.toLowerCase();document.querySelectorAll(".goalos-v56-route").forEach(a=>a.style.display=a.textContent.toLowerCase().includes(q)?"grid":"none")}})</script><div class="goalos-v56-route-list">' + ''.join(rows) + '</div><div class="goalos-v56-metrics">')

def RENDER_SEARCH(routes):
    rows=''.join(f'<a class="goalos-v56-route" href="{html.escape(r)}"><span>Route</span><strong>{html.escape(PAGES.get(r,(r,))[0] if r in PAGES else r)}</strong><span>Open →</span></a>' for r in sorted(routes))
    base=render_page('search.html','GoalOS Search','Find the right page.','Browser-local command search across the complete public proof surface.','search')
    return base.replace('<section class="goalos-v56-section"><div class="goalos-v56-kicker">Canonical surface</div><h2>Everything routes from here.</h2><div class="goalos-v56-metrics">', '<section class="goalos-v56-section"><div class="goalos-v56-kicker">Search</div><h2>Type what you need.</h2><input class="goalos-v56-search" id="routeFilter" placeholder="Search GoalOS routes: RSI, contracts, agents, node, proof, validation..."><script>document.addEventListener("input",e=>{if(e.target.id==="routeFilter"){const q=e.target.value.toLowerCase();document.querySelectorAll(".goalos-v56-route").forEach(a=>a.style.display=a.textContent.toLowerCase().includes(q)?"grid":"none")}})</script><div class="goalos-v56-route-list">' + rows + '</div><div class="goalos-v56-metrics">')

RENDER_PAGE = render_page

ALIASES = {'goalos.html': 'goalos-command-center.html', 'start.html': 'goalos-command-center.html', 'pathfinder.html': 'site-map.html', 'registry.html': 'route-registry.html', 'trust.html': 'trust-boundary.html', 'token.html': 'token-boundary.html', 'mission.html': 'goalos-command-center.html', 'agents.html': 'agi-agent-workbench.html', 'agi-agents.html': 'agi-agent-workbench.html'}

def write(path, text):
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(text, encoding='utf-8')

def detect_root():
    return Path.cwd()

def public_dir(root):
    p=root/'public'; p.mkdir(exist_ok=True); (p/'assets').mkdir(exist_ok=True); return p

def rehydrate(root,pub):
    copied=0
    for snap in sorted((root/'.goalos').glob('tmp/**/payload/public/*.html')):
        target=pub/snap.name
        if not target.exists():
            shutil.copy2(snap,target); copied+=1
    return copied

def strip_prior_v56(text):
    text=re.sub(r'\s*<link[^>]+goalos-sovereign-proof-machine-os-v56\.css[^>]*>','',text,flags=re.I)
    text=re.sub(r'\s*<script[^>]+goalos-sovereign-proof-machine-os-v56\.js[^>]*></script>','',text,flags=re.I)
    text=re.sub(r'\s*<script[^>]+goalos-route-registry-v56\.js[^>]*></script>','',text,flags=re.I)
    return text

def inject_assets(path):
    text=path.read_text(encoding='utf-8',errors='ignore')
    text=strip_prior_v56(text)
    if '<head' not in text.lower():
        text='<!doctype html><html><head><meta charset="utf-8"></head><body>'+text+'</body></html>'
    insert='<link rel="stylesheet" href="assets/goalos-sovereign-proof-machine-os-v56.css"><script defer src="assets/goalos-route-registry-v56.js"></script><script defer src="assets/goalos-sovereign-proof-machine-os-v56.js"></script>'
    text=re.sub(r'</head>',insert+'</head>',text,flags=re.I,count=1)
    if '<body' in text.lower():
        text=re.sub(r'<body([^>]*)>',lambda m: '<body'+m.group(1)+' class="goalos-v56">' if 'class=' not in m.group(1).lower() else '<body'+re.sub(r'class=["\']([^"\']*)["\']', lambda c: 'class="'+c.group(1)+' goalos-v56"', m.group(1), count=1, flags=re.I)+'>',text,flags=re.I,count=1)
    path.write_text(text,encoding='utf-8')

def sanitize_public(pub):
    hits=[]
    for path in pub.rglob('*'):
        if path.is_file() and path.suffix.lower() in ['.html','.js','.css','.json','.md']:
            txt=path.read_text(encoding='utf-8',errors='ignore')
            old=txt
            for a,b in REPL.items(): txt=txt.replace(a,b)
            if txt!=old: path.write_text(txt,encoding='utf-8')
    for path in pub.rglob('*'):
        if path.is_file() and path.suffix.lower() in ['.html','.js','.css']:
            txt=path.read_text(encoding='utf-8',errors='ignore')
            for f in FORBIDDEN:
                if f in txt: hits.append({'file':str(path.relative_to(pub.parent)),'pattern':f})
    return hits

def asset_placeholder(pub, rel):
    dest=(pub/rel).resolve()
    if not str(dest).startswith(str(pub.resolve())): return
    dest.parent.mkdir(parents=True, exist_ok=True)
    if dest.exists(): return
    if dest.suffix=='.css': dest.write_text('/* GoalOS compatibility asset */\n',encoding='utf-8')
    elif dest.suffix=='.js': dest.write_text('/* GoalOS compatibility asset: browser-local no-op */\n',encoding='utf-8')
    elif dest.suffix=='.svg': dest.write_text('<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 80 80"><rect width="80" height="80" rx="18" fill="#67ffd6"/><text x="40" y="50" text-anchor="middle" font-size="38" font-family="Arial" font-weight="900" fill="#061018">α</text></svg>',encoding='utf-8')
    elif dest.suffix=='.json': dest.write_text(json.dumps({'status':'available','boundary':'preserved','externalActions':0},indent=2),encoding='utf-8')
    else: dest.write_text('',encoding='utf-8')

def ensure_internal_targets(pub):
    broken=[]; created=[]
    attrs=re.compile(r'(?:href|src)=["\']([^"\']+)["\']',re.I)
    for html_path in list(pub.rglob('*.html')):
        text=html_path.read_text(encoding='utf-8',errors='ignore')
        base=html_path.parent
        for url in attrs.findall(text):
            if not url or url.startswith(('#','http:','https:','mailto:','tel:','data:','javascript:')): continue
            rel=url.split('#')[0].split('?')[0]
            if not rel: continue
            target=(base/rel).resolve()
            if not str(target).startswith(str(pub.resolve())): continue
            if target.exists(): continue
            if rel.endswith('/'):
                target=target/'index.html'
            if rel.endswith('.html') or target.suffix=='.html':
                target.parent.mkdir(parents=True,exist_ok=True)
                title=target.stem.replace('-',' ').title()
                target.write_text(PAGE_FALLBACK(title, target.name),encoding='utf-8')
                created.append(str(target.relative_to(pub.parent)))
            else:
                asset_placeholder(pub, str(target.relative_to(pub)))
                created.append(str(target.relative_to(pub.parent)))
    # root compatibility json/assets often referenced from archive pages
    for rel in ['site-status.json','search_index.json','search-index.json','assets/goalos.css','assets/goalos.js','assets/goalos-mark.svg']:
        asset_placeholder(pub, rel); created.append('public/'+rel)
    return created

def PAGE_FALLBACK(title, filename):
    return RENDER_PAGE(filename,title,'Discoverable route.','This compatibility route remains discoverable and routes users back into the canonical GoalOS proof surface.','search')

def html_title(path):
    try:
        txt=path.read_text(encoding='utf-8',errors='ignore')[:4000]
        m=re.search(r'<title>(.*?)</title>',txt,re.I|re.S)
        if m: return re.sub(r'\s+',' ',m.group(1)).strip()
        h=re.search(r'<h1[^>]*>(.*?)</h1>',txt,re.I|re.S)
        if h: return re.sub('<[^<]+?>','',h.group(1)).strip()
    except Exception: pass
    return path.stem.replace('-',' ').title()

def build_registry(pub):
    routes=[]
    for path in sorted(pub.rglob('*.html')):
        if '/archive/' in str(path).replace('\\','/'): continue
        rel=str(path.relative_to(pub)).replace('\\','/')
        routes.append({'route':rel,'title':html_title(path),'category':category_for(rel),'canonical':rel in PAGES})
    write(pub/'assets/goalos-route-registry-v56.js','window.GOALOS_ROUTE_REGISTRY_V56 = '+json.dumps(routes,indent=2)+';')
    write(pub/'route-registry.json',json.dumps({'version':VERSION,'routes':routes,'boundary':'preserved','externalActions':0},indent=2))
    return routes

def category_for(r):
    s=r.lower()
    if any(x in s for x in ['rsi','loop','move37','move-37']): return 'RSI / Loop'
    if any(x in s for x in ['agent','foundry']): return 'AGI Agents'
    if 'node' in s: return 'AGI Nodes'
    if any(x in s for x in ['validat','verifier']): return 'Validation'
    if any(x in s for x in ['contract','mainnet','token']): return 'Contracts / Token'
    if any(x in s for x in ['proof','evidence','docket','ledger']): return 'Proof / Evidence'
    if any(x in s for x in ['trust','privacy','boundary','security','data']): return 'Trust & Boundary'
    if any(x in s for x in ['search','map','health','registry','all-pages','404']): return 'Navigation'
    return 'Additional'

def audit(pub):
    broken=[]
    attrs=re.compile(r'(?:href|src)=["\']([^"\']+)["\']',re.I)
    for html_path in pub.rglob('*.html'):
        text=html_path.read_text(encoding='utf-8',errors='ignore')
        base=html_path.parent
        for url in attrs.findall(text):
            if not url or url.startswith(('#','http:','https:','mailto:','tel:','data:','javascript:')): continue
            rel=url.split('#')[0].split('?')[0]
            if not rel: continue
            target=(base/rel).resolve()
            if not str(target).startswith(str(pub.resolve())): continue
            if not target.exists(): broken.append({'file':str(html_path.relative_to(pub.parent)),'target':rel})
    forbidden=[]
    for path in pub.rglob('*'):
        if path.is_file() and path.suffix.lower() in ['.html','.js','.css']:
            txt=path.read_text(encoding='utf-8',errors='ignore')
            for f in FORBIDDEN:
                if f in txt: forbidden.append({'file':str(path.relative_to(pub.parent)),'pattern':f})
    return broken, forbidden

def main():
    root=detect_root(); pub=public_dir(root)
    rehydrated=rehydrate(root,pub)
    write(pub/'assets/goalos-sovereign-proof-machine-os-v56.css',CSS)
    write(pub/'assets/goalos-sovereign-proof-machine-os-v56.js',JS)
    # canonical page writes
    for fn,(title,sub,desc,prof) in PAGES.items():
        write(pub/fn, RENDER_PAGE(fn,title,sub,desc,prof))
    for alias,target in ALIASES.items():
        write(pub/alias, RENDER_PAGE(alias,'GoalOS Route','Canonical route alias.',f'This route opens the canonical GoalOS surface: {target}.','search').replace('</main>',f'<p><a class="goalos-v56-btn goalos-v56-primary" href="{target}">Open canonical page</a></p></main>'))
    # inject assets on remaining pages and sanitize
    for path in pub.rglob('*.html'):
        if path.name not in PAGES and path.name not in ALIASES:
            try: inject_assets(path)
            except Exception: pass
    created=ensure_internal_targets(pub)
    forbidden=sanitize_public(pub)
    routes=build_registry(pub)
    # Generate all-pages and search after registry
    write(pub/'all-pages.html', RENDER_ALL([r['route'] for r in routes]))
    write(pub/'site-map.html', RENDER_ALL([r['route'] for r in routes]))
    write(pub/'search.html', RENDER_SEARCH([r['route'] for r in routes]))
    routes=build_registry(pub)
    broken,forbidden=audit(pub)
    report={'version':VERSION,'status':'passed' if not broken and not forbidden else 'failed','publicPages':len(list(pub.rglob('*.html'))),'currentRoutesIndexed':len(routes),'rehydratedPages':rehydrated,'createdCompatibility':created[:500],'forbiddenBrowserApiHits':forbidden,'brokenInternalLinksOrAssets':broken,'boundary':'preserved','externalActions':0,'productionAuthorization':'not_granted','empiricalSotaClaim':'not_claimed','walletTransactionSupport':'not_enabled','pageSpecificAutonomousDemos':True,'canonicalSurfaces':sorted(PAGES)}
    (root/'reports').mkdir(exist_ok=True); (root/'evidence/demo').mkdir(parents=True,exist_ok=True); (root/'content/goalos').mkdir(parents=True,exist_ok=True); (root/'docs/website').mkdir(parents=True,exist_ok=True)
